const BANK = [{"num": 1, "title": "Packet Forwarding (supporting 3.1.a)", "questions": [{"id": "1.1", "q": "A switch receives a unicast frame whose destination MAC address is not in its MAC address table. What does the switch do?", "options": ["Drops the frame", "Floods the frame out all ports in the same VLAN except the ingress port", "Sends the frame to the default gateway", "Buffers the frame until the address is learned"], "answer": [1], "explanation": "Unknown unicast frames are flooded within the VLAN (except the receiving port)."}, {"id": "1.2", "q": "How many bytes does an 802.1Q tag add to an Ethernet frame, and where is it inserted?", "options": ["8 bytes, before the destination MAC", "4 bytes, between the source MAC and Type/Length fields", "4 bytes, appended after the FCS", "2 bytes, inside the payload"], "answer": [1], "explanation": "The 4-byte 802.1Q tag sits between the source MAC and Type/Length fields; the FCS is recalculated."}, {"id": "1.3", "q": "Traffic on the native VLAN of an 802.1Q trunk is sent how?", "options": ["Tagged with VLAN 1", "Tagged with the native VLAN ID", "Untagged", "Dropped unless explicitly allowed"], "answer": [2], "explanation": "Native VLAN traffic is untagged on 802.1Q trunks; a native VLAN mismatch can merge VLANs."}, {"id": "1.4", "q": "Which device boundary separates broadcast domains by default?", "options": ["Hub", "Layer 2 switch", "Router", "Repeater"], "answer": [2], "explanation": "Routers (or SVIs/routed ports) bound broadcast domains; switches only bound collision domains."}, {"id": "1.5", "q": "Which command displays the VLANs currently allowed and forwarding on a trunk link?", "options": ["show vlan brief", "show interfaces trunk", "show spanning-tree summary", "show etherchannel summary"], "answer": [1], "explanation": "`show interfaces trunk` shows allowed, active, and forwarding VLANs per trunk."}]}, {"num": 2, "title": "Spanning Tree Protocol (3.1.c)", "questions": [{"id": "2.1", "q": "How is the STP root bridge elected?", "options": ["Highest bridge priority; highest MAC breaks ties", "Lowest bridge priority; lowest MAC breaks ties", "Lowest MAC address only", "Highest port cost"], "answer": [1], "explanation": "Lowest bridge ID wins: priority first, then lowest system MAC."}, {"id": "2.2", "q": "On a non-root switch, the root port is the port with the:", "options": ["Lowest port number", "Lowest cost path to the root bridge", "Highest bandwidth, regardless of path", "Lowest MAC address neighbor"], "answer": [1], "explanation": "Root port = lowest accumulated root path cost; ties broken by neighbor bridge ID, port priority, port number."}, {"id": "2.3", "q": "Which 802.1D port states exist, in order, when a port comes up?", "options": ["Listening, learning, blocking, forwarding", "Blocking, listening, learning, forwarding", "Learning, listening, forwarding", "Disabled, forwarding"], "answer": [1], "explanation": "Blocking → listening → learning → forwarding (~30 s with default timers)."}, {"id": "2.4", "q": "In RSTP (802.1W), which port role provides an alternate path to the root and stays discarding?", "options": ["Backup port", "Designated port", "Alternate port", "Edge port"], "answer": [2], "explanation": "Alternate ports back up the root port. Backup ports back up a designated port on the same segment."}, {"id": "2.5", "q": "What is the default 802.1D-era short-mode path cost for a 1 Gbps link?", "options": ["100", "19", "4", "1"], "answer": [2], "explanation": "Short-mode costs: 10 Mbps=100, 100 Mbps=19, 1 Gbps=4, 10 Gbps=2."}, {"id": "2.6", "q": "Two switches are connected back to back. Both ports claim designated. Which values are compared, in order, to resolve the tie?", "options": ["Port priority, then port number", "Root path cost, bridge ID, port priority, port number", "Bridge MAC only", "Interface bandwidth, then duplex"], "answer": [1], "explanation": "Designated port election: lowest root path cost, then lowest bridge ID, then port priority/number."}, {"id": "2.7", "q": "RSTP can rapidly transition a port to forwarding without proposal/agreement when the port is:", "options": ["A point-to-point designated port", "An edge port (PortFast)", "A root port on a shared segment", "Any half-duplex port"], "answer": [1], "explanation": "Edge ports skip proposal/agreement and go straight to forwarding."}, {"id": "2.8", "q": "Which timer defines how long a switch waits, by default, before aging out a BPDU from a neighbor in classic STP?", "options": ["Hello (2 s)", "Forward delay (15 s)", "Max age (20 s)", "Aging (300 s)"], "answer": [2], "explanation": "Max age (20 s) is how long superior BPDU info is retained before being aged out."}, {"id": "2.9", "q": "Refer to the output. Which statement about SW2 is correct?", "options": ["SW2 is the root bridge for VLAN 10", "SW2 is not the root; it reaches the root via Gi1/0/24 at cost 4, and Gi1/0/23 is a blocked alternate path", "Gi1/0/23 is down", "The root bridge has priority 32778"], "exhibit": "SW2# show spanning-tree vlan 10\n\nVLAN0010\n  Spanning tree enabled protocol rstp\n  Root ID    Priority    24586\n             Address     0017.5a4b.c801\n             Cost        4\n             Port        24 (GigabitEthernet1/0/24)\n             Hello Time   2 sec  Max Age 20 sec  Forward Delay 15 sec\n\n  Bridge ID  Priority    32778  (priority 32768 sys-id-ext 10)\n             Address     0023.04ee.be01\n\nInterface           Role Sts Cost      Prio.Nbr Type\n------------------- ---- --- --------- -------- ----\nGi1/0/23            Altn BLK 4         128.23   P2p\nGi1/0/24            Root FWD 4         128.24   P2p", "answer": [1], "explanation": "Root ID and Bridge ID differ, so SW2 is not root. Gi1/0/24 is the root port (FWD); Gi1/0/23 is an alternate (Altn/BLK) backup path. On the root bridge, Root ID = Bridge ID and the output adds \"This bridge is the root.\""}]}, {"num": 3, "title": "Advanced STP Tuning (3.1.c)", "questions": [{"id": "3.1", "q": "Root guard is enabled on a designated port. What happens when a superior BPDU arrives on that port?", "options": ["The port is err-disabled permanently", "The port enters root-inconsistent state and blocks until superior BPDUs stop", "The switch becomes the new root", "The BPDU is ignored silently"], "answer": [1], "explanation": "Root guard blocks (root-inconsistent) only while superior BPDUs are received, then auto-recovers."}, {"id": "3.2", "q": "BPDU guard is best deployed on which ports?", "options": ["Uplinks between distribution and core", "PortFast-enabled access ports facing end hosts", "Trunk ports only", "The root bridge's designated ports"], "answer": [1], "explanation": "BPDU guard protects the edge: hosts should never send BPDUs."}, {"id": "3.3", "q": "A port protected by BPDU guard receives a BPDU. The port:", "options": ["Blocks for twice the forward delay", "Goes err-disabled", "Becomes a root port", "Filters the BPDU and stays forwarding"], "answer": [1], "explanation": "BPDU guard err-disables the port; recovery is manual or via errdisable recovery."}, {"id": "3.4", "q": "Which feature should you configure so the root bridge role is deterministic in your campus?", "options": ["Leave all priorities at 32768", "Lower the priority (e.g., 0 or 4096) on the intended root and set a secondary", "Enable BPDU filter globally", "Raise port costs on the root"], "answer": [1], "explanation": "Explicitly set primary/secondary root priorities; never rely on defaults."}, {"id": "3.5", "q": "What does STP PortFast do?", "options": ["Increases port speed", "Skips listening/learning so the port forwards immediately", "Forces the port to become a root port", "Disables BPDU processing"], "answer": [1], "explanation": "PortFast transitions edge ports straight to forwarding (and suppresses TCN generation on flap)."}, {"id": "3.6", "q": "Which command/feature automatically recovers an err-disabled port after a timeout?", "options": ["errdisable recovery cause bpduguard", "spanning-tree backbonefast", "shutdown / no shutdown is the only option", "spanning-tree pathcost method long"], "answer": [0], "explanation": "`errdisable recovery cause ...` with a recovery interval re-enables the port automatically."}, {"id": "3.7", "q": "Why is BPDU filter on access ports riskier than BPDU guard?", "options": ["It err-disables ports too aggressively", "It can silently allow a loop because BPDUs are neither sent nor processed", "It changes the root bridge", "It only works on trunks"], "answer": [1], "explanation": "Filtering BPDUs removes loop detection on that port entirely; guard fails safe, filter fails open."}, {"id": "3.8", "q": "Refer to the log. What happened, and what is required to restore the port (assuming no recovery timer is configured)?", "options": ["Root guard blocked the port; it recovers when superior BPDUs stop", "A BPDU arrived on a BPDU guard port; the port is err-disabled and needs shutdown/no shutdown (or errdisable recovery) to come back", "The port flapped due to UDLD", "BPDU filter dropped a BPDU; no action needed"], "exhibit": "%SPANTREE-2-BLOCK_BPDUGUARD: Received BPDU on port Gi1/0/5 with\n BPDU Guard enabled. Disabling port.\n%PM-4-ERR_DISABLE: bpduguard error detected on Gi1/0/5,\n putting Gi1/0/5 in err-disable state", "answer": [1], "explanation": "BPDU guard err-disables on any received BPDU (a switch was likely plugged into an access port). Unlike root guard, it does not self-recover; bounce the port or configure `errdisable recovery cause bpduguard`."}]}, {"num": 4, "title": "Multiple Spanning Tree Protocol (3.1.c)", "questions": [{"id": "4.1", "q": "Which three parameters must match for two switches to be in the same MST region?", "options": ["Hostname, domain, VTP version", "Region name, revision number, VLAN-to-instance mapping", "Bridge priority, MAC, max age", "IOS version, region name, VLAN list"], "answer": [1], "explanation": "Name, revision, and the VLAN-to-instance mapping table (a digest of it) must match exactly."}, {"id": "4.2", "q": "In MST, which instance always exists and interacts with non-MST switches?", "options": ["MSTI 1", "IST (instance 0)", "CST instance 4094", "PVST instance per VLAN"], "answer": [1], "explanation": "Instance 0 (IST) runs on all links in the region and represents the region to the CST."}, {"id": "4.3", "q": "The main scalability benefit of MST over Rapid PVST+ is:", "options": ["Faster hello timers", "One spanning-tree instance can carry many VLANs", "It eliminates BPDUs", "It removes the need for a root bridge"], "answer": [1], "explanation": "A few instances replace per-VLAN topologies, cutting BPDU and CPU/TCAM load."}, {"id": "4.4", "q": "How does an MST region appear to an external PVST+/RSTP switch?", "options": ["As one logical switch", "As a separate instance per VLAN", "As a routing domain", "It is invisible"], "answer": [0], "explanation": "The whole region collapses into a single logical bridge from the outside (CST view)."}, {"id": "4.5", "q": "VLANs 10–20 are mapped to MSTI 1, but VLAN 15's traffic must take a different path. What must you do?", "options": ["Change VLAN 15's priority in MSTI 1", "Map VLAN 15 to a different instance (configuration change across the region)", "Configure per-VLAN cost inside MSTI 1", "Nothing; MST balances automatically"], "answer": [1], "explanation": "Path control in MST is per instance; moving a VLAN requires updating the mapping on every region switch."}, {"id": "4.6", "q": "Where is MST instance/VLAN mapping configured?", "options": ["Interface mode", "spanning-tree mst configuration mode (then name/revision/instance mappings)", "VTP server only", "Via DTP negotiation"], "answer": [1], "explanation": "`spanning-tree mst configuration` submode holds name, revision, and instance mappings."}]}, {"num": 5, "title": "VLAN Trunks and EtherChannel Bundles (3.1.a, 3.1.b)", "questions": [{"id": "5.1", "q": "Which DTP mode combination does NOT form a trunk?", "options": ["desirable + desirable", "desirable + auto", "auto + auto", "trunk + auto"], "answer": [2], "explanation": "auto+auto: both wait passively; no trunk. (trunk+auto works because trunk mode actively sends DTP.)"}, {"id": "5.2", "q": "What is the safest way to configure a trunk you fully control?", "options": ["switchport mode dynamic desirable both sides", "switchport mode trunk + switchport nonegotiate on both sides", "switchport mode access", "Leave DTP defaults"], "answer": [1], "explanation": "Static trunk with DTP disabled (`nonegotiate`) removes negotiation attack surface and flap risk."}, {"id": "5.3", "q": "A trunk comes up but VLAN 30 traffic fails across it. `show interfaces trunk` shows VLAN 30 not in the allowed list. Fix?", "options": ["switchport trunk allowed vlan add 30", "switchport trunk allowed vlan 30 (replacing the list)", "Recreate VLAN 30", "Change native VLAN to 30"], "answer": [0], "explanation": "Use the `add` keyword; omitting it overwrites the entire allowed list (a classic outage cause)."}, {"id": "5.4", "q": "Which LACP mode combination forms an EtherChannel?", "options": ["passive + passive", "active + passive", "on + active", "auto + desirable"], "answer": [1], "explanation": "LACP needs at least one active side: active+active or active+passive."}, {"id": "5.5", "q": "PAgP \"desirable\" corresponds most closely to which LACP mode?", "options": ["passive", "active", "on", "standby"], "answer": [1], "explanation": "PAgP desirable and LACP active both initiate negotiation (auto/passive only respond)."}, {"id": "5.6", "q": "Which mismatch will prevent an interface from joining an EtherChannel bundle?", "options": ["Different interface descriptions", "Different speed/duplex or switchport mode/allowed VLANs", "Different cable lengths", "Different port numbers"], "answer": [1], "explanation": "Members must match speed, duplex, mode, native/allowed VLANs, etc., or they're suspended."}, {"id": "5.7", "q": "Mode \"on\" is configured on one side and LACP active on the other. Result?", "options": ["Channel forms via LACP", "Channel does not form (and may err-disable/loop risk)", "PAgP takes over", "Half the links bundle"], "answer": [1], "explanation": "\"on\" sends no protocol; LACP side won't bundle. Static \"on\" must be used on both sides."}, {"id": "5.8", "q": "Which command shows bundle status with flags such as (P) bundled and (s) suspended?", "options": ["show etherchannel summary", "show interfaces status", "show lacp neighbor detail only", "show port-channel database"], "answer": [0], "explanation": "`show etherchannel summary` flags: P bundled, s/S suspended, D down, w waiting."}, {"id": "5.9", "q": "Refer to the output. Why is the port-channel not forming?", "options": ["The ports are err-disabled", "SW1 runs LACP but its member ports are stand-alone (I) — the far side is not negotiating LACP (e.g., mode on or PAgP)", "The VLANs are pruned", "Po1 needs an IP address"], "exhibit": "SW1# show etherchannel summary\nFlags:  D - down        P - bundled in port-channel\n        I - stand-alone s - suspended\n        ...\nGroup  Port-channel  Protocol    Ports\n------+-------------+-----------+--------------------------\n1      Po1(SD)        LACP      Gi1/0/1(I)   Gi1/0/2(I)", "answer": [1], "explanation": "(I) stand-alone means LACP got no partner response. Fix the far end to LACP active/passive (or both sides static on)."}, {"id": "5.10", "q": "Both switch ports are configured identically as shown. Why is the link an access port?", "options": ["DTP is disabled", "Both sides are dynamic auto — neither initiates DTP negotiation, so no trunk forms", "The native VLANs mismatch", "VTP pruned the trunk"], "exhibit": "SW1# show interfaces Gi1/0/13 switchport | include Mode\nAdministrative Mode: dynamic auto\nOperational Mode: static access\n\nSW2# show interfaces Gi1/0/13 switchport | include Mode\nAdministrative Mode: dynamic auto\nOperational Mode: static access", "answer": [1], "explanation": "auto+auto is the classic non-trunk combo: both passively wait. Set one side desirable, or hardcode `switchport mode trunk`."}, {"id": "5.11", "q": "Refer to the log. What is the most likely cause?", "options": ["LACP system priority mismatch", "A member-port attribute mismatch — Gi1/0/2 negotiated a different speed, so it is suspended from the bundle", "Spanning tree blocked the port", "The port-channel number is wrong"], "exhibit": "%EC-5-CANNOT_BUNDLE2: Gi1/0/2 is not compatible with Gi1/0/1\n and will be suspended (speed of Gi1/0/2 is 100M, Gi1/0/1 is 1000M)", "answer": [1], "explanation": "All bundle members must match speed/duplex/mode/VLAN settings; mismatched ports get suspended (s/(s) in the summary)."}]}, {"num": 6, "title": "IP Routing Essentials (3.2.a, 3.2.d, 2.2.a)", "questions": [{"id": "6.1", "q": "Order these default administrative distances from most to least preferred: OSPF, eBGP, EIGRP (internal), static.", "options": ["static (1), eBGP (20), EIGRP (90), OSPF (110)", "static (1), EIGRP (90), eBGP (20), OSPF (110)", "eBGP (20), static (1), OSPF (110), EIGRP (90)", "static (5), eBGP (20), OSPF (90), EIGRP (110)"], "answer": [0], "explanation": "Connected 0, static 1, eBGP 20, EIGRP 90, OSPF 110, IS-IS 115, RIP 120, iBGP 200."}, {"id": "6.2", "q": "Two routes to the same prefix come from OSPF (metric 50) and EIGRP internal (metric 30000). Which is installed?", "options": ["OSPF, lower metric", "EIGRP, lower AD (90 vs 110)", "Both, ECMP", "Neither; AD tie"], "answer": [1], "explanation": "AD decides between different protocols; metric only compares routes within the same protocol."}, {"id": "6.3", "q": "Which statement about link-state vs. advanced distance vector protocols is true?", "options": ["OSPF routers share full topology within an area; EIGRP routers know only what neighbors advertise", "EIGRP floods LSAs", "OSPF supports unequal-cost load balancing natively", "EIGRP requires areas"], "answer": [0], "explanation": "Link-state floods topology (LSDB); EIGRP is advanced distance vector (\"routing by rumor\" plus DUAL/feasible successors)."}, {"id": "6.4", "q": "What makes a static route \"floating\"?", "options": ["A next hop on a different subnet", "An AD set higher than the primary route so it installs only on failure", "A route to null0", "Recursive lookup"], "answer": [1], "explanation": "e.g., `ip route 0.0.0.0 0.0.0.0 203.0.113.1 250` as backup."}, {"id": "6.5", "q": "A recursive static route requires:", "options": ["The next hop be resolved via another routing table lookup", "An exit interface only", "A /32 mask", "CEF disabled"], "answer": [0], "explanation": "Next-hop-only static routes need a second lookup to find the exit interface."}, {"id": "6.6", "q": "Policy-based routing is applied:", "options": ["Outbound on the egress interface", "Inbound on the interface receiving the traffic to be policy-routed", "Globally only", "Only to locally generated traffic"], "answer": [1], "explanation": "`ip policy route-map X` goes on the ingress interface; `ip local policy` handles router-generated traffic."}, {"id": "6.7", "q": "In a route map used for PBR, which action forwards matched traffic to a specific router?", "options": ["set ip default next-hop", "set ip next-hop", "match ip next-hop", "set interface null0"], "answer": [1], "explanation": "`set ip next-hop` overrides the routing table for matched packets (default next-hop applies only when no specific route exists)."}, {"id": "6.8", "q": "Which commands place an interface into VRF \"RED\" and verify RED's routes? (Choose two.)", "options": ["vrf forwarding RED (interface)", "ip vrf RED (interface)", "show ip route vrf RED", "show vrf route RED"], "answer": [0, 2], "explanation": "Modern syntax `vrf forwarding RED` (older: `ip vrf forwarding`); verify with `show ip route vrf RED`. Note: assigning an interface to a VRF removes its IP address."}, {"id": "6.9", "q": "Refer to the routing table. Which next hop is used for a packet to 10.1.1.99?", "options": ["192.168.12.2, because EIGRP has the lowest AD", "192.168.13.3, because OSPF metric 20 is lowest", "192.168.14.4, because 10.1.1.0/24 is the longest prefix match", "The packet is dropped (ambiguous routes)"], "exhibit": "R1# show ip route | include 10.\nD        10.0.0.0/8 [90/130816] via 192.168.12.2\nO        10.1.0.0/16 [110/20] via 192.168.13.3\nS        10.1.1.0/24 [1/0] via 192.168.14.4", "answer": [2], "explanation": "Longest prefix match is evaluated BEFORE AD or metric. /24 beats /16 and /8 regardless of protocol."}, {"id": "6.10", "q": "OSPF and a static route to the same prefix are configured. Why does the routing table show only the OSPF route, and when would that change?", "options": ["The static route is malformed", "The static is a floating route (AD 250 > 110); it installs only if the OSPF route disappears", "OSPF always beats static routes", "10.9.9.9 is unreachable"], "exhibit": "R1# show running-config | include ip route\nip route 172.16.5.0 255.255.255.0 10.9.9.9 250\n\nR1# show ip route 172.16.5.0\nRouting entry for 172.16.5.0/24\n  Known via \"ospf 1\", distance 110, metric 65, type intra area", "answer": [1], "explanation": "AD 250 makes it a backup. AD only breaks ties between sources for the SAME prefix; the floating static installs the moment OSPF withdraws 172.16.5.0/24."}]}, {"num": 7, "title": "EIGRP (3.2.a)", "questions": [{"id": "7.1", "q": "By default, EIGRP's composite metric uses which two values?", "options": ["Bandwidth and delay", "Bandwidth and reliability", "Delay and load", "Hop count and MTU"], "answer": [0], "explanation": "K1 (bandwidth) and K3 (delay) are on by default; reliability/load are off."}, {"id": "7.2", "q": "The feasibility condition states that a route qualifies as a feasible successor when:", "options": ["Its reported distance is lower than the feasible distance of the successor", "Its feasible distance is lower than the reported distance", "It has the same metric as the successor", "It is learned on the same interface"], "answer": [0], "explanation": "RD < FD guarantees the neighbor isn't routing through you (loop-free)."}, {"id": "7.3", "q": "What is the main benefit of a feasible successor?", "options": ["Load balancing is disabled", "Immediate, loop-free failover without going Active (no DUAL query)", "Lower administrative distance", "Automatic summarization"], "answer": [1], "explanation": "FS routes are pre-validated backups; convergence is nearly instant."}, {"id": "7.4", "q": "Which parameters must match for two routers to become EIGRP neighbors? (Choose two.)", "options": ["Autonomous system number", "K values", "Hello timers", "Router IDs"], "answer": [0, 1], "explanation": "AS number and K values must match. EIGRP hello timers do NOT need to match (unlike OSPF)."}, {"id": "7.5", "q": "What does the EIGRP `variance 2` command enable?", "options": ["Two equal-cost paths only", "Unequal-cost load balancing across feasible successors whose metric is within 2x the successor's FD", "Doubling of the hello timer", "Two EIGRP processes"], "answer": [1], "explanation": "Variance multiplier allows unequal-cost paths, but only routes meeting the feasibility condition."}, {"id": "7.6", "q": "EIGRP \"Stuck in Active\" occurs when:", "options": ["A neighbor doesn't reply to a query for a route that lost its successor", "The hold timer expires", "Two routers have duplicate router IDs", "Variance is misconfigured"], "answer": [0], "explanation": "Unanswered queries leave the route Active until the timer expires and the neighborship resets."}, {"id": "7.7", "q": "Which multicast address does EIGRP use for hellos (IPv4)?", "options": ["224.0.0.5", "224.0.0.10", "224.0.0.13", "224.0.0.18"], "answer": [1], "explanation": "224.0.0.10 (OSPF uses .5/.6, PIM .13, VRRP .18)."}, {"id": "7.8", "q": "Refer to the topology table. Is the path via 10.1.13.3 a feasible successor?", "options": ["Yes — its total metric 196608 is acceptable", "No — its reported distance 131328 is not lower than the FD 131072, so the feasibility condition fails", "Yes — any second path is a feasible successor", "No — it is on a different interface"], "exhibit": "R1# show ip eigrp topology 10.20.0.0/16\nEIGRP-IPv4 Topology Entry for AS(100)/ID(1.1.1.1) for 10.20.0.0/16\n  State is Passive, Query origin flag is 1, 1 Successor(s), FD is 131072\n        via 10.1.12.2 (131072/130816), GigabitEthernet0/1\n        via 10.1.13.3 (196608/131328), GigabitEthernet0/2", "answer": [1], "explanation": "FS requires RD < FD. Here RD (second number, 131328) ≥ FD (131072), so this path waits for DUAL computation if the successor fails. The numbers in parentheses are (FD via this path / neighbor's RD)."}]}, {"num": 8, "title": "OSPF (3.2.a, 3.2.b)", "questions": [{"id": "8.1", "q": "Which parameters must match for an OSPF adjacency to form? (Choose three.)", "options": ["Hello and dead intervals", "Area ID", "Subnet/mask on the link", "Router ID", "Process ID"], "answer": [0, 1, 2], "explanation": "Timers, area, subnet (plus auth, stub flags, MTU for full adjacency). RIDs must DIFFER; process IDs are locally significant."}, {"id": "8.2", "q": "Two OSPF routers on Ethernet remain in 2WAY state with each other. Most likely reason?", "options": ["MTU mismatch", "Both are DROTHERs — full adjacency forms only with DR/BDR on broadcast networks", "Authentication failure", "Different process IDs"], "answer": [1], "explanation": "On broadcast networks, DROTHER-DROTHER pairs stay in 2WAY by design. Stuck 2WAY with a DR is a problem; 2WAY between DROTHERs is normal."}, {"id": "8.3", "q": "Neighbors are stuck in EXSTART/EXCHANGE. Classic cause?", "options": ["MTU mismatch", "Wrong network type", "Duplicate area", "Passive interface"], "answer": [0], "explanation": "Database description exchange fails when MTUs differ (or use `ip ospf mtu-ignore`)."}, {"id": "8.4", "q": "How is the OSPF router ID chosen if not configured manually?", "options": ["Lowest IP on any interface", "Highest loopback IP, else highest active physical interface IP", "The interface MAC", "Random 32-bit value"], "answer": [1], "explanation": "Manual `router-id` > highest loopback > highest physical interface IP."}, {"id": "8.5", "q": "DR election on a broadcast segment prefers:", "options": ["Lowest priority, then lowest RID", "Highest priority, then highest RID (priority 0 = never DR)", "First router booted, always preempted", "Highest interface bandwidth"], "answer": [1], "explanation": "Highest priority wins (default 1); ties broken by highest RID. No preemption once elected."}, {"id": "8.6", "q": "Default hello/dead timers on broadcast and point-to-point networks?", "options": ["30/120", "10/40", "5/20", "10/30"], "answer": [1], "explanation": "10/40 on broadcast and p2p; 30/120 on NBMA types."}, {"id": "8.7", "q": "What does `passive-interface` do in OSPF?", "options": ["Stops advertising that interface's subnet", "Advertises the subnet but sends no hellos (no adjacencies on that interface)", "Drops OSPF traffic inbound", "Sets cost to infinity"], "answer": [1], "explanation": "Subnet stays advertised; hellos stop. Standard for user-facing interfaces."}, {"id": "8.8", "q": "Which network type does OSPF assume on a GigabitEthernet interface by default, and what's a common tuning on a p2p Ethernet link?", "options": ["Point-to-point; change to broadcast", "Broadcast; change to point-to-point to skip DR election and speed adjacency", "Non-broadcast; add neighbor statements", "Point-to-multipoint; nothing needed"], "answer": [1], "explanation": "Ethernet defaults to broadcast; `ip ospf network point-to-point` removes DR/BDR overhead on router-to-router links."}, {"id": "8.9", "q": "Which command enables OSPF on an interface without a network statement?", "options": ["ip ospf 1 area 0 (interface mode)", "router ospf 1 interface Gi0/1", "ospf enable", "network interface Gi0/1"], "answer": [0], "explanation": "Interface-level `ip ospf <pid> area <area>` is the modern alternative to network statements."}, {"id": "8.10", "q": "Refer to the output. What is the most likely cause?", "options": ["Hello timer mismatch", "MTU mismatch between the two interfaces — database description exchange keeps failing", "Wrong area ID", "Authentication failure"], "exhibit": "R1# show ip ospf neighbor\n\nNeighbor ID     Pri   State           Dead Time   Address      Interface\n2.2.2.2           1   EXSTART/DR      00:00:33    10.1.12.2    Gi0/0\n\n%OSPF-5-ADJCHG: Process 1, Nbr 2.2.2.2 on Gi0/0 from EXSTART to DOWN,\n Neighbor Down: Too many retransmissions", "answer": [1], "explanation": "Stuck EXSTART/EXCHANGE with retransmission failures is the signature MTU-mismatch symptom. Match MTUs or use `ip ospf mtu-ignore`."}, {"id": "8.11", "q": "Refer to the debug. What prevents the adjacency?", "options": ["Area mismatch", "Hello/dead interval mismatch — received 10/40 vs configured 30/120 (often a broadcast vs. non-broadcast network type mismatch)", "Duplicate router ID", "Passive interface"], "exhibit": "R1# debug ip ospf hello\nOSPF-1 HELLO Gi0/0: Rcv hello from 2.2.2.2 area 0 10.1.12.2\nOSPF-1 HELLO Gi0/0: Mismatched hello parameters from 10.1.12.2\nOSPF-1 HELLO Gi0/0: Dead R 40 C 120, Hello R 10 C 30", "answer": [1], "explanation": "The debug spells it out: R = received (10/40, broadcast defaults), C = configured (30/120, NBMA defaults). Timers (and usually network types) must agree."}, {"id": "8.12", "q": "Refer to the output on a broadcast segment. Does the 2WAY state indicate a problem?", "options": ["Yes — all neighbors must reach FULL", "No — R4 and 3.3.3.3 are both DROTHERs; on broadcast networks DROTHERs go FULL only with the DR and BDR", "Yes — 3.3.3.3 has an MTU mismatch", "No — 2WAY means the link is down intentionally"], "exhibit": "R4# show ip ospf neighbor\n\nNeighbor ID     Pri   State           Dead Time   Address      Interface\n3.3.3.3           1   2WAY/DROTHER    00:00:31    10.1.0.3     Gi0/1\n1.1.1.1           1   FULL/DR         00:00:34    10.1.0.1     Gi0/1\n2.2.2.2           1   FULL/BDR        00:00:38    10.1.0.2     Gi0/1", "answer": [1], "explanation": "Expected behavior. DROTHER↔DROTHER pairs stop at 2WAY by design; full adjacencies form only with the DR/BDR."}]}, {"num": 9, "title": "Advanced OSPF (3.2.a, 3.2.b)", "questions": [{"id": "9.1", "q": "Match the LSA type: which LSA carries inter-area routes and which carries external routes?", "options": ["Type 1 inter-area, Type 2 external", "Type 3 inter-area (from ABR), Type 5 external (from ASBR)", "Type 5 inter-area, Type 7 intra-area", "Type 2 inter-area, Type 4 external"], "answer": [1], "explanation": "T1 router, T2 network, T3 inter-area summary, T4 ASBR locator, T5 external, T7 NSSA external."}, {"id": "9.2", "q": "Which area type blocks Type 5 LSAs but allows redistribution inside the area via Type 7?", "options": ["Stub", "Totally stubby", "NSSA", "Backbone"], "answer": [2], "explanation": "NSSA: no Type 5s in, but local ASBRs inject Type 7 (converted to Type 5 at the ABR)."}, {"id": "9.3", "q": "A totally stubby area receives which routes from its ABR?", "options": ["All inter-area and external routes", "Only a default route (plus intra-area)", "External routes only", "Nothing"], "answer": [1], "explanation": "Totally stubby ABRs send a single Type 3 default; no other inter-area or external routes."}, {"id": "9.4", "q": "Where is `area X range` configured and what does it do?", "options": ["On the ASBR; summarizes external routes", "On the ABR; summarizes Type 3 inter-area advertisements for that area's prefixes", "On any router; filters LSAs", "On the DR; compresses the LSDB"], "answer": [1], "explanation": "`area range` summarizes that area's routes as they leave through the ABR."}, {"id": "9.5", "q": "To summarize redistributed (external) routes, use:", "options": ["area range on the ABR", "summary-address on the ASBR", "distribute-list in", "ip summary-address ospf on the interface"], "answer": [1], "explanation": "External summarization happens at the redistribution point (ASBR)."}, {"id": "9.6", "q": "Which OSPF filtering method prevents routes from being installed in the local RIB but does NOT stop LSA flooding?", "options": ["area filter-list", "distribute-list in", "summary-address not-advertise", "passive-interface"], "answer": [1], "explanation": "distribute-list in affects only the local RIB; the LSDB and downstream flooding are untouched."}, {"id": "9.7", "q": "Every OSPF area must connect to area 0. If a remote area can't physically touch the backbone, the classic fix is:", "options": ["A second OSPF process", "A virtual link across the transit area", "Redistribution", "NSSA conversion"], "answer": [1], "explanation": "Virtual links extend area 0 logically across a transit area."}, {"id": "9.8", "q": "OSPF external Type 1 (E1) routes differ from E2 because E1:", "options": ["Adds internal path cost to the external metric; E2 keeps only the redistribution metric", "Is always preferred less than E2", "Cannot be summarized", "Only exists in NSSAs"], "answer": [0], "explanation": "E1 = external + internal cost (grows with distance); E2 (default) = fixed external metric."}, {"id": "9.9", "q": "Refer to the routing table entries. What do the markings on the two routes indicate?", "options": ["Both are intra-area routes", "IA = inter-area route learned via an ABR (Type 3 LSA); E2 = external route with a fixed metric of 20 that does not grow along the internal path", "IA = external; E2 = stub route", "E2's metric includes the full internal cost"], "exhibit": "R5# show ip route ospf\nO IA  172.16.30.0/24 [110/35] via 10.5.5.1, 00:10:11, Gi0/0\nO E2  198.51.100.0/24 [110/20] via 10.5.5.1, 00:10:11, Gi0/0", "answer": [1], "explanation": "O IA comes from another area through an ABR. O E2 (the redistribution default) keeps its seed metric end to end; E1 would add internal cost as the route propagates."}]}, {"num": 10, "title": "OSPFv3 (3.2.b)", "questions": [{"id": "10.1", "q": "OSPFv3 adjacencies are formed using which source addresses?", "options": ["Global unicast addresses", "Link-local addresses (FE80::/10)", "Site-local addresses", "The router ID"], "answer": [1], "explanation": "Hellos/adjacencies use link-local source addresses; global prefixes are carried in LSAs."}, {"id": "10.2", "q": "How is OSPFv3 enabled on an interface?", "options": ["network statements with IPv6 prefixes", "Interface command (e.g., ospfv3 1 ipv6 area 0 / ipv6 ospf 1 area 0)", "Automatically when IPv6 is enabled", "Via DHCPv6"], "answer": [1], "explanation": "OSPFv3 is interface-enabled; there are no network statements."}, {"id": "10.3", "q": "What is true of the OSPFv3 router ID?", "options": ["It's a 128-bit IPv6 address", "It remains a 32-bit value and may need manual configuration if no IPv4 addresses exist", "It's derived from the MAC always", "It's optional"], "answer": [1], "explanation": "RID is still 32-bit; an IPv6-only router requires `router-id` to be set manually."}, {"id": "10.4", "q": "Which OSPFv3 feature lets one process carry both IPv4 and IPv6 routes?", "options": ["Dual stack LSAs", "Address families (AF) support", "NAT-PT", "Type 9 LSAs"], "answer": [1], "explanation": "OSPFv3 address families allow IPv4 and IPv6 under one v3 process."}, {"id": "10.5", "q": "In OSPFv3, prefix information was moved out of router/network LSAs into:", "options": ["Type 5 only", "Intra-Area Prefix LSAs (and Link LSAs for link-local info)", "Hello packets", "Type 4 LSAs"], "answer": [1], "explanation": "Decoupling topology from prefixes means prefix changes don't force SPF runs."}, {"id": "10.6", "q": "Which multicast groups does OSPFv3 use?", "options": ["FF02::5 (all OSPF routers) and FF02::6 (DR routers)", "FF02::A and FF02::B", "FF02::1 and FF02::2", "FF05::5 only"], "answer": [0], "explanation": "FF02::5 and FF02::6, mirroring 224.0.0.5/6 in OSPFv2."}]}, {"num": 11, "title": "BGP (3.2.c)", "questions": [{"id": "11.1", "q": "BGP sessions are established over:", "options": ["UDP 179", "TCP 179", "IP protocol 89", "TCP 22"], "answer": [1], "explanation": "TCP 179; one side initiates, the session rides normal TCP."}, {"id": "11.2", "q": "A neighbor relationship is eBGP rather than iBGP when:", "options": ["The neighbor is in a different autonomous system", "The neighbor is more than one hop away", "Multihop is configured", "The routers share an IGP"], "answer": [0], "explanation": "Different ASN = eBGP (AD 20); same ASN = iBGP (AD 200)."}, {"id": "11.3", "q": "Which BGP states will you see, in order, for a successfully established session?", "options": ["Down, Init, Up", "Idle, Connect, OpenSent, OpenConfirm, Established", "Listening, Learning, Forwarding", "Active, Passive, Established"], "answer": [1], "explanation": "Idle → Connect → OpenSent → OpenConfirm → Established (Active = retrying TCP)."}, {"id": "11.4", "q": "A session flaps between Idle and Active. Most likely cause?", "options": ["The neighbor's AS is correct", "TCP reachability problems or wrong neighbor IP/AS configuration", "Too many prefixes", "Route reflector missing"], "answer": [1], "explanation": "Idle/Active cycling is almost always TCP/reachability or mismatched neighbor statements."}, {"id": "11.5", "q": "For the `network 10.10.0.0 mask 255.255.0.0` command to advertise the prefix, what must be true?", "options": ["Nothing; BGP originates it unconditionally", "An exactly matching route (prefix AND mask) must exist in the local RIB", "The prefix must be connected", "A neighbor must request it"], "answer": [1], "explanation": "BGP's network statement advertises only what already exists exactly in the RIB."}, {"id": "11.6", "q": "By default, what TTL do eBGP packets use, and what does that imply?", "options": ["TTL 255; neighbors can be anywhere", "TTL 1; neighbors must be directly connected unless ebgp-multihop/ttl-security is configured", "TTL 64; up to 64 hops", "TTL 0; loopbacks required"], "answer": [1], "explanation": "eBGP defaults to TTL 1 — hence \"directly connected neighbors\" in the exam topic."}, {"id": "11.7", "q": "When a route is advertised to an eBGP peer, which attributes change by default? (Choose two.)", "options": ["Next hop is set to the advertising router", "Local AS is prepended to AS_Path", "MED is removed always", "Weight is copied"], "answer": [0, 1], "explanation": "eBGP updates rewrite next-hop to self and prepend the sender's ASN to AS_Path."}, {"id": "11.8", "q": "Which command summarizes BGP neighbor state and prefixes received in one view?", "options": ["show bgp neighbors detail", "show ip bgp summary", "show ip route bgp", "show bgp table"], "answer": [1], "explanation": "`show ip bgp summary`: neighbor, AS, uptime, state/prefixes received."}, {"id": "11.9", "q": "Refer to the output. What does the \"Active\" state actually mean here?", "options": ["The session is established and actively exchanging routes", "The session is NOT established — R1 is actively retrying the TCP connection (check reachability, neighbor IP/AS, TTL)", "The neighbor is in a different VRF", "BGP is converging normally; wait"], "exhibit": "R1# show ip bgp summary\nNeighbor        V    AS MsgRcvd MsgSent   TblVer  InQ OutQ Up/Down  State/PfxRcd\n10.1.1.2        4 65002       0       0        1    0    0 never    Active", "answer": [1], "explanation": "\"Active\" is the most misleading word in BGP: it means trying (and failing) to establish TCP. Idle/Active cycling = fix reachability or neighbor config."}, {"id": "11.10", "q": "Refer to the output. The session is up, but no routes are arriving from the peer. Where do you look first?", "options": ["The TCP session — it is down", "The session is Established (state column shows a prefix count); investigate whether the peer is advertising anything and whether inbound filters are stripping routes", "The AS number — it must match ours", "The Up/Down timer — it must reach 24 hours"], "exhibit": "R1# show ip bgp summary\nNeighbor        V    AS MsgRcvd MsgSent   TblVer  InQ OutQ Up/Down  State/PfxRcd\n10.1.1.2        4 65002     124     130        5    0    0 01:58:23        0", "answer": [1], "explanation": "When State/PfxRcd shows a NUMBER, the session is Established. 0 prefixes for 2 hours points to the peer's outbound policy or your inbound filters — not the session."}]}, {"num": 12, "title": "Advanced BGP: Best Path (3.2.c)", "questions": [{"id": "12.1", "q": "Place these best-path criteria in evaluation order: AS_Path length, weight, local preference, origin.", "options": ["Weight → local preference → AS_Path length → origin", "Local preference → weight → origin → AS_Path", "AS_Path → weight → local preference → origin", "Origin → AS_Path → weight → local preference"], "answer": [0], "explanation": "Weight (highest) → LocPref (highest) → locally originated → shortest AS_Path → origin → lowest MED → eBGP>iBGP → lowest IGP cost to next hop → oldest → lowest RID."}, {"id": "12.2", "q": "Which best-path attribute is Cisco-proprietary and only locally significant to the router where it's set?", "options": ["Local preference", "Weight", "MED", "Origin"], "answer": [1], "explanation": "Weight never leaves the router; highest wins."}, {"id": "12.3", "q": "Local preference is used to influence:", "options": ["How traffic exits your AS (higher wins, shared via iBGP)", "How neighbors enter your AS", "Only eBGP sessions", "TTL values"], "answer": [0], "explanation": "LocPref (default 100) is AS-wide outbound path policy."}, {"id": "12.4", "q": "With all earlier criteria tied, a route via eBGP vs. one via iBGP:", "options": ["iBGP wins", "eBGP wins", "Random choice", "Both install (ECMP)"], "answer": [1], "explanation": "eBGP-learned beats iBGP-learned at that step."}, {"id": "12.5", "q": "Origin codes are preferred in which order?", "options": ["incomplete < EGP < IGP", "IGP < EGP < incomplete (IGP best)", "EGP best", "They're never compared"], "answer": [1], "explanation": "IGP (network statement) beats EGP beats incomplete (redistributed)."}, {"id": "12.6", "q": "Which attribute is a *suggestion to a neighboring AS* about which entry point to use into your AS (lower preferred)?", "options": ["Weight", "Local preference", "MED", "Community"], "answer": [2], "explanation": "MED (metric) signals preferred ingress to the adjacent AS; lowest wins, compared by default only from the same AS."}, {"id": "12.7", "q": "Refer to the output. Why was path #2 selected as best?", "options": ["Lower router ID", "Weight and local preference tie, so the shorter AS_Path (one AS vs. two) wins", "Lower MED", "It was learned first"], "exhibit": "R1# show ip bgp 203.0.113.0/24\nBGP routing table entry for 203.0.113.0/24, version 14\nPaths: (2 available, best #2)\n  65010 65020\n    192.168.1.1 from 192.168.1.1 (10.0.0.1)\n      Origin IGP, localpref 100, metric 0, valid, external\n  65030\n    192.168.2.2 from 192.168.2.2 (10.0.0.2)\n      Origin IGP, localpref 100, metric 0, valid, external, best", "answer": [1], "explanation": "Both paths show localpref 100 (and default weight). Next decision point in the algorithm is AS_Path length: \"65030\" (1 hop) beats \"65010 65020\" (2 hops)."}]}, {"num": 13, "title": "Multicast (3.3.d)", "questions": [{"id": "13.1", "q": "Which range holds all IPv4 multicast addresses, and which sub-range is reserved for SSM?", "options": ["224.0.0.0/4 overall; 232.0.0.0/8 for SSM", "239.0.0.0/8 overall; 224.0.0.0/24 for SSM", "224.0.0.0/8 overall; 238.0.0.0/8 for SSM", "240.0.0.0/4 overall; 232.0.0.0/16 for SSM"], "answer": [0], "explanation": "224/4 total; 224.0.0.0/24 link-local; 232/8 SSM; 239/8 admin-scoped."}, {"id": "13.2", "q": "What is the purpose of the RPF check?", "options": ["Verify the receiver is authorized", "Accept multicast only on the interface that is the unicast path back to the source/RP, preventing loops", "Encrypt the stream", "Elect the PIM DR"], "answer": [1], "explanation": "RPF: if the packet didn't arrive on the interface used to reach the source/RP via unicast routing, drop it."}, {"id": "13.3", "q": "In PIM Sparse Mode, what role does the Rendezvous Point play?", "options": ["It is the root of the shared tree (*,G) where sources are first learned by receivers", "It forwards all traffic permanently", "It replaces IGMP", "It blocks SPT switchover"], "answer": [0], "explanation": "Receivers join toward the RP; sources register to it; RP joins source trees on their behalf."}, {"id": "13.4", "q": "(*,G) vs (S,G) entries: which statement is correct?", "options": ["(*,G) = shared tree rooted at the RP; (S,G) = shortest-path tree rooted at the source", "(*,G) = source tree; (S,G) = shared tree", "Both are identical", "(S,G) exists only in dense mode"], "answer": [0], "explanation": "Shared tree (*,G) via RP; source tree (S,G) is the optimal path."}, {"id": "13.5", "q": "Which IGMP version is required for SSM, and why?", "options": ["IGMPv1; it floods reports", "IGMPv2; it supports leave messages", "IGMPv3; receivers specify the source they want (INCLUDE mode)", "Any version"], "answer": [2], "explanation": "SSM has no RP; the receiver must name the source — only IGMPv3 can."}, {"id": "13.6", "q": "What did IGMPv2 add over v1?", "options": ["Source filtering", "Leave Group messages and querier election", "Encryption", "SSM mapping"], "answer": [1], "explanation": "Leave messages cut leave latency; querier election picks the lowest IP."}, {"id": "13.7", "q": "Which protocol lets RPs in different PIM domains exchange information about active sources?", "options": ["MSDP (Source-Active messages over TCP between RPs)", "BSR", "Auto-RP", "IGMP proxy"], "answer": [0], "explanation": "MSDP peers (typically RPs) exchange SA messages so domains learn external sources. (Supplement: MSDP isn't covered in the OCG.)"}, {"id": "13.8", "q": "Bidirectional PIM differs from PIM-SM because bidir:", "options": ["Builds only shared trees — no (S,G)/SPT state — scaling many-to-many apps", "Floods everywhere then prunes", "Requires IGMPv3", "Removes the RP"], "answer": [0], "explanation": "Bidir uses only (*,G) state both up and down the shared tree — ideal for many-to-many."}, {"id": "13.9", "q": "What does IGMP snooping do on a switch?", "options": ["Blocks all multicast", "Constrains multicast flooding to ports with interested receivers by listening to IGMP messages", "Routes multicast between VLANs", "Elects the RP"], "answer": [1], "explanation": "Snooping builds a Layer 2 forwarding map from IGMP joins instead of flooding."}, {"id": "13.10", "q": "A receiver-side router learns of a source via the shared tree and then joins the SPT. This behavior is called:", "options": ["RPF failover", "SPT switchover (default at the first packet on Cisco routers)", "Prune override", "Asserts"], "answer": [1], "explanation": "IOS defaults `ip pim spt-threshold 0`: switch to SPT immediately."}, {"id": "13.11", "q": "Multicast from source 10.1.50.10 arrives on interface Gi0/1. Refer to the output — what happens to the stream?", "options": ["It is forwarded normally", "It fails the RPF check and is dropped — the unicast path back to the source is via Gi0/2, not Gi0/1 where the traffic arrived", "It is flooded to all PIM neighbors", "It is tunneled to the RP"], "exhibit": "R3# show ip rpf 10.1.50.10\nRPF information for ? (10.1.50.10)\n  RPF interface: GigabitEthernet0/2\n  RPF neighbor: ? (10.1.23.2)\n  RPF route/mask: 10.1.50.0/24\n  RPF type: unicast (ospf 1)", "answer": [1], "explanation": "RPF accepts multicast only on the interface the router would use to reach the source via unicast routing. Arriving on any other interface = drop. Fix the unicast topology or the multicast tree, not the symptom."}]}, {"num": 14, "title": "Quality of Service (1.4)", "questions": [{"id": "14.1", "q": "Which QoS model uses RSVP to reserve bandwidth end to end, and which uses per-hop behaviors based on markings?", "options": ["IntServ = RSVP reservations; DiffServ = per-hop behaviors", "DiffServ = RSVP; IntServ = PHB", "Best effort = RSVP", "Both use RSVP"], "answer": [0], "explanation": "IntServ = signaled reservations (RSVP); DiffServ = markings + PHBs, the scalable norm."}, {"id": "14.2", "q": "In the MQC, configuration objects are applied in which structure?", "options": ["class-map (classify) → policy-map (actions) → service-policy (apply to interface)", "policy-map → class-map → access-list", "service-policy → class-map → policy-map", "route-map → policy-map → interface"], "answer": [0], "explanation": "Classify with class-maps, define actions in policy-maps, attach with service-policy."}, {"id": "14.3", "q": "Which DSCP value is standard for voice bearer traffic?", "options": ["CS3 (24)", "AF41 (34)", "EF (46)", "Default (0)"], "answer": [2], "explanation": "EF/DSCP 46 for voice; CS3/AF31 commonly for call signaling."}, {"id": "14.4", "q": "In AF marking \"AF31,\" what do the 3 and the 1 represent?", "options": ["Class 3, drop precedence 1 (low drop probability)", "Priority 3, queue 1", "Bandwidth 3 Mbps, burst 1 MB", "CoS 3, ToS 1"], "answer": [0], "explanation": "AFxy: x = class (queue), y = drop precedence within that class."}, {"id": "14.5", "q": "Policing vs. shaping — which statement is correct?", "options": ["Policing buffers excess; shaping drops it", "Policing drops or re-marks excess immediately; shaping buffers and smooths it (adding delay)", "Both buffer", "Shaping is inbound-only"], "answer": [1], "explanation": "Police = drop/re-mark (no delay added); shape = buffer/delay to a target rate."}, {"id": "14.6", "q": "Interpret: `priority 512` under a class in a policy-map does what that `bandwidth 512` does not?", "options": ["Guarantees minimum bandwidth only", "Creates a low-latency (LLQ) strict-priority queue, policed to 512 kbps during congestion", "Reserves memory", "Disables queuing"], "answer": [1], "explanation": "`priority` = LLQ with built-in policer; `bandwidth` = CBWFQ minimum guarantee without strict priority."}, {"id": "14.7", "q": "What does WRED do?", "options": ["Drops all excess traffic at queue full (tail drop)", "Randomly drops lower-priority packets early as queues fill, to avoid global TCP synchronization", "Re-marks DSCP to 0", "Fragments large packets"], "answer": [1], "explanation": "Weighted random early detection drops selectively pre-congestion based on DSCP/precedence."}, {"id": "14.8", "q": "A policy-map applied with `service-policy input PM-X` on Gi0/1 will:", "options": ["Shape outbound traffic", "Classify/act on traffic entering Gi0/1", "Apply to all interfaces", "Fail; policies are output-only"], "answer": [1], "explanation": "Direction is set at attach time; input policies act on ingress traffic."}, {"id": "14.9", "q": "Refer to the configuration. During congestion on Gi0/0, how is VOICE traffic treated?", "options": ["Guaranteed a 1000 kbps minimum, sharing leftover bandwidth", "Served first from a strict-priority (LLQ) queue but policed to 1000 kbps during congestion", "Shaped to 1000 kbps at all times", "Dropped first because priority queues drop early"], "exhibit": "policy-map WAN-EDGE\n class VOICE\n  priority 1000\n class CRITICAL-DATA\n  bandwidth 2000\n class class-default\n  fair-queue\n  random-detect dscp-based\n\ninterface GigabitEthernet0/0\n service-policy output WAN-EDGE", "answer": [1], "explanation": "`priority` = LLQ: strict priority with a built-in conditional policer so voice can't starve other classes. `bandwidth` (CRITICAL-DATA) is a CBWFQ minimum guarantee without strict priority."}, {"id": "14.10", "q": "Refer to the configuration. What happens to SCAVENGER traffic that exceeds 8000 bps?", "options": ["It is buffered and sent later", "It is dropped immediately — policing does not queue or delay excess traffic", "It is re-marked to EF", "It is fragmented"], "exhibit": "policy-map EDGE-IN\n class SCAVENGER\n  police 8000 conform-action transmit exceed-action drop", "answer": [1], "explanation": "Police drops (or re-marks) on the spot; shape would buffer. The exceed-action here is explicit: drop."}]}, {"num": 15, "title": "IP Services (3.3.a, 3.3.b, 3.3.c, 1.1.b)", "questions": [{"id": "15.1", "q": "In NTP, what does \"stratum\" measure?", "options": ["Hop count to the NTP server's reference clock (lower = closer/more authoritative)", "Packet delay in ms", "Server CPU load", "Encryption strength"], "answer": [0], "explanation": "Stratum 0 = reference clock, 1 = directly attached server; devices prefer lower stratum."}, {"id": "15.2", "q": "Interpret: `ntp server 10.1.1.1 prefer` vs `ntp peer 10.1.1.2`:", "options": ["Both are identical", "server = this device synchronizes to 10.1.1.1; peer = mutual synchronization possible with 10.1.1.2", "peer = one-way sync", "server = broadcast mode"], "answer": [1], "explanation": "`server` is client mode toward that address; `peer` allows mutual (symmetric) sync."}, {"id": "15.3", "q": "Why can PTP (IEEE 1588) achieve far better accuracy than NTP?", "options": ["It uses TCP", "Hardware timestamping and on-path clock roles (boundary/transparent clocks) remove network jitter", "It polls more often only", "It uses GPS exclusively"], "answer": [1], "explanation": "PTP's precision comes from hardware timestamps plus boundary/transparent clocks correcting on-path delay."}, {"id": "15.4", "q": "In PTP, which device recalculates time and acts as a master to downstream slaves?", "options": ["Transparent clock", "Boundary clock", "Ordinary slave", "Stratum-1 server"], "answer": [1], "explanation": "Boundary clocks terminate and regenerate PTP; transparent clocks just correct residence time in the packet."}, {"id": "15.5", "q": "Default HSRP behavior: a router with higher priority comes online after another router is already Active. What happens?", "options": ["It immediately takes over", "Nothing — HSRP does not preempt by default", "Both go Active", "The group resets"], "answer": [1], "explanation": "HSRP preempt is off by default (VRRP's is on). Enable `standby X preempt` for deterministic roles."}, {"id": "15.6", "q": "Which virtual MAC pattern indicates HSRPv1 group 10?", "options": ["0000.5e00.010a", "0000.0c07.ac0a", "0007.b400.0a00", "0000.0c9f.f00a"], "answer": [1], "explanation": "HSRPv1: 0000.0c07.acXX (XX = group hex). VRRP: 0000.5e00.01XX."}, {"id": "15.7", "q": "VRRP differs from HSRP in which ways? (Choose two.)", "options": ["VRRP is an open standard", "VRRP preempts by default", "VRRP is Cisco proprietary", "VRRP cannot track objects"], "answer": [0, 1], "explanation": "VRRP = IETF standard, preempts by default, multicasts to 224.0.0.18 (master/backup roles)."}, {"id": "15.8", "q": "What is the purpose of object tracking with an FHRP?", "options": ["Authentication", "Decrement priority when an upstream interface/route fails so the peer takes over", "Load balancing", "Faster hellos"], "answer": [1], "explanation": "e.g., `standby 1 track 100 decrement 20` ties gateway role to upstream health."}, {"id": "15.9", "q": "A packet from inside host 192.168.1.10 is translated to 203.0.113.5 before leaving. In NAT terms, 203.0.113.5 is the:", "options": ["Inside local address", "Inside global address", "Outside local address", "Outside global address"], "answer": [1], "explanation": "Inside local = private as seen inside; inside global = the inside host as seen from outside."}, {"id": "15.10", "q": "Which configuration enables PAT for an inside network using the outgoing interface address?", "options": ["ip nat inside source list 1 interface Gi0/0 overload", "ip nat outside source static ...", "ip nat inside source static tcp ...", "ip nat pool only"], "answer": [0], "explanation": "list + interface + `overload` = many-to-one PAT on the egress interface IP."}, {"id": "15.11", "q": "Refer to the output. The local router's priority is then raised to 110. What happens, and why?", "options": ["R2 immediately becomes Active", "Nothing changes until the current Active fails — the P column is empty, so preemption is not configured", "The group renegotiates and both go Active", "The virtual IP moves to R2"], "exhibit": "R2# show standby brief\n                     P indicates configured to preempt.\nInterface   Grp  Pri P State    Active          Standby         Virtual IP\nVl10        10   90    Standby  10.1.10.3       local           10.1.10.1", "answer": [1], "explanation": "HSRP does not preempt by default. Higher priority matters only at election time or with `standby 10 preempt` configured."}, {"id": "15.12", "q": "Refer to the output. Which statement is correct?", "options": ["This is static NAT — one-to-one mappings", "Multiple inside hosts share inside global 203.0.113.5 distinguished by port — this is PAT (overload); 192.168.1.10 appears externally as 203.0.113.5", "198.51.100.7 is the inside global address", "The translations are broken — ports should differ from the local ports"], "exhibit": "R1# show ip nat translations\nPro  Inside global       Inside local        Outside local       Outside global\ntcp  203.0.113.5:34012   192.168.1.10:34012  198.51.100.7:443    198.51.100.7:443\ntcp  203.0.113.5:51877   192.168.1.22:51877  198.51.100.9:443    198.51.100.9:443", "answer": [1], "explanation": "Same inside global IP + unique ports = PAT. Inside global = how inside hosts appear outside; outside global = the real destination."}, {"id": "15.13", "q": "Refer to the output. What does it tell you?", "options": ["R4 is a stratum-16 authoritative server", "R4 has not synchronized to any NTP source — stratum 16 is the \"unsynchronized\" marker; check ntp server config and reachability", "NTP is working normally", "The hardware clock failed"], "exhibit": "R4# show ntp status\nClock is unsynchronized, stratum 16, no reference clock", "answer": [1], "explanation": "Stratum 16 means \"no valid time source.\" Verify the server address, reachability, and (if used) NTP authentication; sync also takes several minutes to settle."}]}, {"num": 16, "title": "Overlay Tunnels (2.2.b, 2.3.a, 2.3.b)", "questions": [{"id": "16.1", "q": "GRE is identified by which IP protocol number, and what notable capability does it add over plain IPsec tunnel mode?", "options": ["50; encryption", "47; can carry multicast/routing protocols and non-IP traffic", "89; compression", "51; authentication"], "answer": [1], "explanation": "GRE = IP protocol 47; multiprotocol + multicast support is why IGPs can run over it."}, {"id": "16.2", "q": "A GRE tunnel flaps repeatedly with \"recursive routing\" messages. Cause?", "options": ["MTU too large", "The tunnel destination is being learned through the tunnel itself", "Keepalives disabled", "Wrong tunnel key"], "answer": [1], "explanation": "The route to the tunnel endpoint must stay in the underlay; learning it via the tunnel collapses it."}, {"id": "16.3", "q": "Which IPsec protocol provides encryption, and which provides only integrity/authentication?", "options": ["AH encrypts; ESP authenticates", "ESP (IP 50) can encrypt and authenticate; AH (IP 51) authenticates only — and breaks with NAT", "Both encrypt", "IKE encrypts data traffic"], "answer": [1], "explanation": "ESP = confidentiality + integrity (NAT-friendly with NAT-T); AH = integrity only, NAT-incompatible."}, {"id": "16.4", "q": "IKE's two phases accomplish what?", "options": ["Phase 1: secure management channel (ISAKMP SA); Phase 2: negotiate IPsec SAs for data", "Phase 1: data; Phase 2: keys", "Both negotiate routing", "Phase 2 is optional always"], "answer": [0], "explanation": "Phase 1 builds the secure negotiation channel; Phase 2 builds the data-plane SAs."}, {"id": "16.5", "q": "Why is GRE over IPsec popular for site-to-site VPNs running an IGP?", "options": ["It's faster than plain GRE", "GRE carries the routing protocol/multicast; IPsec encrypts the whole GRE package", "It avoids tunnel interfaces", "It requires no crypto config"], "answer": [1], "explanation": "Combine GRE flexibility with IPsec confidentiality (or use VTI as a cleaner alternative)."}, {"id": "16.6", "q": "In LISP, what do EID and RLOC represent?", "options": ["EID = endpoint identity (host/site prefix); RLOC = the locator (underlay address) of the site's router", "EID = router loopback; RLOC = host address", "Both are MAC addresses", "EID = AS number; RLOC = area"], "answer": [0], "explanation": "LISP splits identity (EID) from location (RLOC), enabling mobility and smaller core tables."}, {"id": "16.7", "q": "Which LISP component answers \"where is this EID?\" queries from ITRs?", "options": ["The VTEP", "The Map Server/Map Resolver (mapping system)", "The RP", "The route reflector"], "answer": [1], "explanation": "ITRs query the MS/MR mapping system — LISP's \"DNS for routing.\" ITR encapsulates; ETR decapsulates."}, {"id": "16.8", "q": "VXLAN encapsulates Layer 2 frames into:", "options": ["GRE over TCP", "UDP (destination port 4789) with a VXLAN header carrying a 24-bit VNI", "ESP", "MPLS labels"], "answer": [1], "explanation": "MAC-in-UDP/4789; the VTEP performs encap/decap."}, {"id": "16.9", "q": "What scale advantage does the 24-bit VNI provide over 802.1Q?", "options": ["~16 million segments vs. 4094 VLANs", "Faster forwarding", "Longer cables", "Lower MTU"], "answer": [0], "explanation": "24 bits ≈ 16.7M VNIs vs. 12-bit VLAN IDs (4094 usable)."}, {"id": "16.10", "q": "Refer to the outputs. Why is the tunnel down?", "options": ["The tunnel key mismatches", "R1 has no route to the tunnel destination 10.2.2.2, so the tunnel cannot be brought up", "GRE keepalives are unsupported", "The MTU is too small"], "exhibit": "R1# show interface Tunnel0\nTunnel0 is up, line protocol is down\n  Hardware is Tunnel\n  Tunnel source 10.1.1.1, destination 10.2.2.2\n\nR1# show ip route 10.2.2.2\n% Network not in table", "answer": [1], "explanation": "A GRE tunnel needs a valid underlay route to its destination. (And remember: if that route later points THROUGH the tunnel itself, you get recursive routing flaps.)"}]}, {"num": 22, "title": "Enterprise Network Architecture (1.1.a, 1.1.b)", "questions": [{"id": "22.1", "q": "A two-tier (collapsed core) design combines which layers?", "options": ["Access and distribution", "Core and distribution", "Core and access", "WAN and core"], "answer": [1], "explanation": "Collapsed core = core + distribution in one layer; fits smaller campuses."}, {"id": "22.2", "q": "When does a three-tier design become appropriate?", "options": ["Never; two-tier always scales", "When multiple distribution blocks must interconnect (large/multi-building campus)", "Only with SD-Access", "When using only Layer 2"], "answer": [1], "explanation": "A dedicated core simplifies interconnecting many distribution blocks."}, {"id": "22.3", "q": "Which functions belong at the distribution layer in a classic campus? (Choose two.)", "options": ["First-hop gateway/policy boundary between L2 access and L3 core", "End-device connectivity and PoE", "Aggregation of access switches and summarization toward the core", "Internet peering"], "answer": [0, 2], "explanation": "Distribution = aggregation, summarization, policy, gateway boundary."}, {"id": "22.4", "q": "SSO provides what on a dual-supervisor switch?", "options": ["Stateful failover of the control plane to the standby supervisor", "Load balancing across supervisors", "Faster STP", "Power redundancy"], "answer": [0], "explanation": "Stateful Switchover keeps state synced to the standby supervisor for sub-second control-plane failover."}, {"id": "22.5", "q": "NSF/graceful restart complements SSO by:", "options": ["Restarting all routing adjacencies immediately", "Continuing to forward on stale CEF entries while routing protocols resync after switchover", "Disabling CEF", "Forcing OSPF to flush LSAs"], "answer": [1], "explanation": "Forwarding continues during routing protocol recovery (with GR/NSR-aware neighbors)."}, {"id": "22.6", "q": "Which are high-availability techniques named in exam topic 1.1.b? (Choose three.)", "options": ["Redundancy", "FHRP", "SSO", "NAT"], "answer": [0, 1, 2], "explanation": "Redundancy, FHRPs, and SSO are the listed HA techniques."}, {"id": "22.7", "q": "In a routed-access design, the L2/L3 boundary moves to:", "options": ["The core", "The access layer (no FHRP/STP between access and distribution)", "The firewall", "The WAN edge"], "answer": [1], "explanation": "Routed access pushes L3 to the access switch, eliminating FHRP/STP convergence dependencies."}]}, {"num": 23, "title": "Fabric Technologies: SD-Access & Catalyst SD-WAN (1.2.a, 1.2.b, 1.3.a, 1.3.b, 4.5)", "questions": [{"id": "23.1", "q": "In SD-Access, which protocols form the control plane and data plane of the fabric?", "options": ["OSPF control, GRE data", "LISP control plane, VXLAN data plane (with TrustSec/SGTs for policy)", "BGP control, MPLS data", "STP control, 802.1Q data"], "answer": [1], "explanation": "LISP (control), VXLAN (data), Cisco TrustSec SGTs (policy) — orchestrated by Catalyst Center."}, {"id": "23.2", "q": "Which SD-Access fabric role tracks endpoint-to-edge mappings (the \"host database\")?", "options": ["Border node", "Control plane node (LISP MS/MR)", "Edge node", "Intermediate node"], "answer": [1], "explanation": "The control plane node runs the LISP Map Server/Resolver tracking EID-to-fabric-edge mappings."}, {"id": "23.3", "q": "Which fabric role connects the SD-Access fabric to external networks?", "options": ["Edge node", "Border node", "Extended node", "WLC"], "answer": [1], "explanation": "Borders translate between fabric and outside (known and unknown/default borders)."}, {"id": "23.4", "q": "How does traditional (non-fabric) campus connect with SD-Access during migration?", "options": ["It cannot", "Through the border (often with a fusion device handling VRF route leaking)", "Via VTP", "Through the control plane node directly"], "answer": [1], "explanation": "Border + fusion router/firewall leaks routes between fabric VNs and the legacy network."}, {"id": "23.5", "q": "In Catalyst SD-WAN, which component is the control-plane brain distributing routing/policy via OMP?", "options": ["SD-WAN Manager (vManage)", "vSmart controller", "vBond orchestrator", "WAN Edge router"], "answer": [1], "explanation": "vSmart distributes routes/policies over OMP; it is the control plane."}, {"id": "23.6", "q": "Which component authenticates and orchestrates initial onboarding, including NAT traversal?", "options": ["vBond (Validator)", "vSmart", "Catalyst Center", "The RP"], "answer": [0], "explanation": "vBond validates devices and brokers initial control connections (works across NAT)."}, {"id": "23.7", "q": "SD-WAN Manager (vManage) provides:", "options": ["Data plane forwarding", "Centralized management — config templates/policies, monitoring, the single pane of glass", "IPsec key generation only", "Underlay routing"], "answer": [1], "explanation": "Management plane: templates, software, monitoring, APIs."}, {"id": "23.8", "q": "Which protocol carries routes, TLOCs, and policy between vSmart and WAN Edge routers?", "options": ["OSPF", "OMP (Overlay Management Protocol)", "LISP", "BGP only"], "answer": [1], "explanation": "OMP advertises prefixes, TLOCs, keys, and policy inside the overlay."}, {"id": "23.9", "q": "Which are commonly cited Catalyst SD-WAN benefits? (Choose two.)", "options": ["Transport independence (MPLS/Internet/LTE) with app-aware routing", "Centralized policy and zero-touch provisioning", "Eliminates the need for security", "Unlimited free bandwidth"], "answer": [0, 1], "explanation": "Transport independence, app-aware routing, central policy, ZTP are the headline benefits; limitations include controller dependency and overlay/underlay complexity."}, {"id": "23.10", "q": "Catalyst Center's four primary workflow areas are:", "options": ["Plan, Build, Run, Bill", "Design, Policy, Provision, Assurance", "Discover, Monitor, Alert, Patch", "Code, Test, Deploy, Operate"], "answer": [1], "explanation": "Design → Policy → Provision → Assurance (topic 4.5; includes AI-powered assurance workflows)."}]}, {"num": 24, "title": "Network Assurance (4.1, 4.2, 4.3, 4.4, 4.5)", "questions": [{"id": "24.1", "q": "Syslog severity levels run 0–7. Which is correct?", "options": ["0 = debugging, 7 = emergency", "0 = emergency, 7 = debugging", "1 = informational", "5 = critical"], "answer": [1], "explanation": "0 emergency, 1 alert, 2 critical, 3 error, 4 warning, 5 notification, 6 informational, 7 debugging."}, {"id": "24.2", "q": "`logging trap 4` sends which messages to the syslog server?", "options": ["Only level 4", "Levels 0 through 4 (emergency..warning)", "Levels 4 through 7", "Nothing until level 7 events occur"], "answer": [1], "explanation": "The trap level is the maximum (least severe) level sent; lower numbers are more severe and always included."}, {"id": "24.3", "q": "What advantage does a conditional debug (e.g., `debug ip packet` with an ACL, or `debug condition interface`) give?", "options": ["More verbose output", "Limits debug output to matching traffic/interfaces, reducing CPU risk on production gear", "Writes directly to NVRAM", "Persists across reloads"], "answer": [1], "explanation": "Conditional debugging scopes output — the safe way to debug in production."}, {"id": "24.4", "q": "How does traceroute discover the path?", "options": ["Sends pings with increasing payload", "Sends probes with incrementing TTL; each hop returns ICMP Time Exceeded", "Queries each router's SNMP agent", "Uses LLDP"], "answer": [1], "explanation": "TTL=1, 2, 3... expirations map the path; the destination answers with port-unreachable (UDP) or echo-reply."}, {"id": "24.5", "q": "Which SNMP version added authentication and encryption, and which mode provides both?", "options": ["v2c; noAuthNoPriv", "v3; authPriv", "v1; authNoPriv", "v3; community strings"], "answer": [1], "explanation": "SNMPv3 authPriv = authentication (MD5/SHA) + privacy (DES/AES). v1/v2c use plaintext communities."}, {"id": "24.6", "q": "Flexible NetFlow requires which three components tied together?", "options": ["Flow record, flow exporter, flow monitor (monitor applied to the interface)", "Sampler, logger, trap", "Class-map, policy-map, service-policy", "Tracker, probe, schedule"], "answer": [0], "explanation": "Record (what to match/collect) → exporter (where to send) → monitor (binds them, applied per interface/direction)."}, {"id": "24.7", "q": "In a flow record, `match` vs `collect` fields differ how?", "options": ["match = key fields that define a unique flow; collect = additional data gathered about it", "collect defines the flow; match is optional", "They're interchangeable", "match is for IPv6 only"], "answer": [0], "explanation": "Key fields distinguish flows; collected fields are extra telemetry (counters, timestamps, etc.)."}, {"id": "24.8", "q": "Which SPAN variant sends mirrored traffic across a Layer 3 network using GRE encapsulation?", "options": ["Local SPAN", "RSPAN", "ERSPAN", "VSPAN"], "answer": [2], "explanation": "ERSPAN = GRE-encapsulated, routable mirroring; SPAN/RSPAN are L2-bound."}, {"id": "24.9", "q": "RSPAN requires what to carry mirrored traffic between switches?", "options": ["A GRE tunnel", "A dedicated RSPAN VLAN trunked end to end (with MAC learning disabled in it)", "A NetFlow exporter", "An IPsec SA"], "answer": [1], "explanation": "The RSPAN VLAN must exist on every switch in the path and be allowed on trunks."}, {"id": "24.10", "q": "Which IP SLA operation is best for measuring one-way jitter/latency for voice, and what must the far end run?", "options": ["icmp-echo; nothing special", "udp-jitter; an IP SLA responder on the target device", "http-get; a web server", "tcp-connect; a route reflector"], "answer": [1], "explanation": "udp-jitter gives jitter/one-way delay/MOS; enable `ip sla responder` on the far router."}, {"id": "24.11", "q": "Refer to the syslog message. What is its severity?", "options": ["5 = critical", "5 = notification — the number after the facility (LINEPROTO) is the severity level", "7 = debugging, from the \"1/0/7\"", "2 = critical, from \"%...-2-\""], "exhibit": "*Jun  9 14:02:11.123: %LINEPROTO-5-UPDOWN: Line protocol on Interface\n GigabitEthernet1/0/7, changed state to down", "answer": [1], "explanation": "Format is %FACILITY-SEVERITY-MNEMONIC. 5 = notification (0 emer, 1 alert, 2 crit, 3 err, 4 warn, 5 notif, 6 info, 7 debug)."}, {"id": "24.12", "q": "Refer to the traceroute. What is the most accurate interpretation?", "options": ["The destination is definitely unreachable", "Hops 3+ are not returning ICMP TTL-exceeded messages — a device may be filtering ICMP or rate-limiting replies; it does not necessarily mean user traffic is dropped there", "Hop 3 has high CPU", "The route loops between hops 3 and 4"], "exhibit": "R1# traceroute 198.51.100.50\n  1 10.1.12.2    1 msec  1 msec  1 msec\n  2 10.1.23.3    2 msec  2 msec  2 msec\n  3  *  *  *\n  4  *  *  *", "answer": [1], "explanation": "Asterisks mean no TTL-exceeded reply came back — commonly ICMP filtering/rate-limiting, not proof of packet loss for real traffic (which the exam loves to test)."}, {"id": "24.13", "q": "Flexible NetFlow is configured as shown, but the cache is always empty. What is missing?", "options": ["A sampler", "The monitor was never applied to an interface (e.g., `ip flow monitor MON input` under Gi0/0)", "The exporter port is wrong", "`collect counter packets` is required"], "exhibit": "flow record REC\n match ipv4 source address\n match ipv4 destination address\n collect counter bytes\n\nflow exporter EXP\n destination 10.99.99.10\n transport udp 2055\n\nflow monitor MON\n record REC\n exporter EXP", "answer": [1], "explanation": "Record + exporter + monitor exist, but a flow monitor collects nothing until applied to an interface with a direction."}, {"id": "24.14", "q": "Refer to the output of a udp-jitter probe targeting another router. What is the most likely fix?", "options": ["Increase the frequency", "Enable `ip sla responder` on the target router — udp-jitter requires a responder", "Change to ICMP jitter", "Reboot the source router"], "exhibit": "R1# show ip sla statistics 10\nIPSLAs Latest Operation Statistics\n\nIPSLA operation id: 10\nType of operation: udp-jitter\n        Latest operation return code: Timeout\nNumber of successes: 0\nNumber of failures: 119", "answer": [1], "explanation": "Timeouts with 0 successes on udp-jitter = no responder answering. The responder must be explicitly enabled on the far-end IOS device."}]}, {"num": 25, "title": "Secure Network Access Control (5.4.a–d)", "questions": [{"id": "25.1", "q": "Which component of a threat-defense design analyzes NetFlow telemetry to detect anomalies inside the network?", "options": ["Cisco Secure Network Analytics (Stealthwatch)", "A standard ACL", "NTP", "EtherChannel guard"], "answer": [0], "explanation": "Secure Network Analytics baselines flows and flags anomalies (data exfil, lateral movement)."}, {"id": "25.2", "q": "What distinguishes a next-generation firewall from a traditional stateful firewall? (Choose two.)", "options": ["Application-layer visibility/control (AVC) regardless of port", "Integrated intrusion prevention and threat intelligence", "Only L3/L4 port-based rules", "No logging"], "answer": [0, 1], "explanation": "NGFW = AVC + NGIPS + identity/threat feeds (e.g., Talos) beyond stateful L3/L4 inspection."}, {"id": "25.3", "q": "Endpoint security such as Cisco Secure Endpoint (AMP) primarily provides:", "options": ["Switch port security", "Malware detection/response on hosts with retrospective analysis of file behavior", "VLAN assignment", "Routing protection"], "answer": [1], "explanation": "Host-resident detection/quarantine, including retrospective verdicts on files seen earlier."}, {"id": "25.4", "q": "In Cisco TrustSec, what replaces IP-based ACL management for segmentation policy?", "options": ["MAC filtering", "Security Group Tags (SGTs) enforced by SGACLs", "VLAN maps only", "NAT rules"], "answer": [1], "explanation": "Policy follows the tag, not the IP — the basis of SD-Access microsegmentation."}, {"id": "25.5", "q": "TrustSec operates in which three functional phases?", "options": ["Classification, propagation, enforcement", "Discovery, marking, drop", "Ingress, transit, egress", "Design, provision, assure"], "answer": [0], "explanation": "Classify (assign SGT at ingress/ISE), propagate (inline tagging or SXP), enforce (SGACLs)."}, {"id": "25.6", "q": "MACsec (802.1AE) provides:", "options": ["End-to-end Layer 3 encryption", "Hop-by-hop Layer 2 encryption at line rate between directly connected devices", "Application encryption", "Wireless encryption"], "answer": [1], "explanation": "Per-link L2 encryption; combine links to cover a path (downlink vs. uplink MACsec)."}, {"id": "25.7", "q": "Which protocol negotiates MACsec session keys?", "options": ["IKEv2", "MKA (MACsec Key Agreement)", "TLS", "OMP"], "answer": [1], "explanation": "MKA handles key exchange (often seeded by 802.1X/EAP or pre-shared CAK)."}, {"id": "25.8", "q": "Which solution serves as the policy decision point for identity-based network access (and distributes SGTs)?", "options": ["Catalyst Center only", "Cisco ISE", "The DHCP server", "The WLC"], "answer": [1], "explanation": "ISE authenticates (802.1X/MAB/WebAuth), authorizes, and assigns SGTs/policy."}]}, {"num": 26, "title": "Device Access Control & Infrastructure Security (5.1.a, 5.1.b, 5.2.a, 5.2.b)", "questions": [{"id": "26.1", "q": "Which configuration restricts which source IPs may SSH to the vty lines?", "options": ["An extended ACL applied with `access-class X in` on line vty", "ip access-group on Gi0/0", "A prefix list", "CoPP only"], "answer": [0], "explanation": "`access-class` on the vty lines filters management access (plus `transport input ssh`)."}, {"id": "26.2", "q": "Why is `username admin secret ...` preferred over `username admin password ...`?", "options": ["secret allows longer names", "secret stores a strong hash (MD5/scrypt/SHA-256 by type) instead of a weak/reversible password", "password is hashed stronger", "No difference"], "answer": [1], "explanation": "`secret` = irreversible hash; `password` (even with service password-encryption type 7) is trivially reversible."}, {"id": "26.3", "q": "In AAA, what are the three A's?", "options": ["Access, Accounting, Auditing", "Authentication (who), Authorization (what they may do), Accounting (what they did)", "Authentication, Association, Access", "Admission, Authorization, Assurance"], "answer": [1], "explanation": "Authentication, Authorization, Accounting."}, {"id": "26.4", "q": "TACACS+ vs RADIUS for device administration — why is TACACS+ preferred? (Choose two.)", "options": ["TACACS+ (TCP 49) encrypts the entire payload and separates authentication from authorization (per-command control)", "RADIUS encrypts everything", "RADIUS (UDP 1812/1813) combines authen/author and encrypts only the password", "TACACS+ is UDP-based"], "answer": [0, 2], "explanation": "Full-payload encryption + granular per-command authorization make TACACS+ the device-admin choice; RADIUS dominates network access (802.1X)."}, {"id": "26.5", "q": "What does `aaa new-model` do, and what's the common safety net with it?", "options": ["Resets all passwords; no safety needed", "Enables AAA processing; define local fallback (e.g., method list ending in `local`) so you're not locked out if servers fail", "Disables line passwords permanently", "Encrypts the config"], "answer": [1], "explanation": "Always configure local fallback before pointing login at AAA servers."}, {"id": "26.6", "q": "Where should an extended ACL generally be placed, and a standard ACL?", "options": ["Extended near the source; standard near the destination", "Both at the core", "Extended near destination; standard near source", "Placement is irrelevant"], "answer": [0], "explanation": "Extended can be precise, so filter early (near source); standard matches only source, so place near destination."}, {"id": "26.7", "q": "What is the purpose of CoPP?", "options": ["Rate-limit/protect traffic destined TO the device's control plane (CPU) using an MQC policy on `control-plane`", "Encrypt management traffic", "Block all ICMP", "Police transit data traffic"], "answer": [0], "explanation": "CoPP polices punted/CPU-bound traffic classes (routing, management, ICMP, undesirable)."}, {"id": "26.8", "q": "In a CoPP policy, why must you be careful with the class-default and with ACLs matching routing protocols?", "options": ["class-default cannot exist", "Dropping/over-policing routing or management protocols can break adjacencies and lock you out", "ACLs aren't supported", "CoPP only matches ICMP"], "answer": [1], "explanation": "Misclassified BGP/OSPF/SSH under an aggressive policer is a self-inflicted outage; always baseline and use conservative rates."}, {"id": "26.9", "q": "Refer to the configuration. Which sessions can reach the CLI of this switch?", "options": ["SSH and Telnet from anywhere", "SSH only, and only from sources in 10.1.50.0/24 (authenticated against local usernames); everything else is denied and logged", "Telnet only from 10.1.50.0/24", "SSH from anywhere, because access-class only filters Telnet"], "exhibit": "ip access-list extended MGMT\n 10 permit tcp 10.1.50.0 0.0.0.255 any eq 22\n 20 deny   ip any any log\n\nline vty 0 4\n access-class MGMT in\n transport input ssh\n login local", "answer": [1], "explanation": "`access-class in` filters vty access by source, `transport input ssh` kills Telnet, `login local` authenticates against local users. The deny logs everything else."}, {"id": "26.10", "q": "Refer to the configuration. The TACACS+ servers become unreachable. What happens to logins?", "options": ["All logins fail until a server returns", "Logins fall back to the local username database — the method list tries TACACS+ first, then local when servers don't respond", "The enable password is used", "Authentication is bypassed entirely"], "exhibit": "aaa new-model\naaa authentication login default group tacacs+ local", "answer": [1], "explanation": "Method lists are tried in order; \"local\" is the lifeline. Note the distinction: fallback occurs when servers are UNREACHABLE, not when they REJECT a login."}]}, {"num": 27, "title": "Virtualization (2.1.a, 2.1.b, 2.1.c)", "questions": [{"id": "27.1", "q": "Type 1 vs Type 2 hypervisors:", "options": ["Type 1 runs on bare metal (ESXi, KVM/Hyper-V); Type 2 runs atop a host OS (VMware Workstation, VirtualBox)", "Type 2 is bare metal", "Both require a host OS", "Type 1 is desktop-only"], "answer": [0], "explanation": "Type 1 = bare metal (production data centers); Type 2 = hosted on a desktop OS."}, {"id": "27.2", "q": "A virtual machine consists of:", "options": ["Shared kernel processes only", "Virtual hardware (vCPU, vRAM, vNIC, virtual disk) running a full guest OS isolated by the hypervisor", "A container image", "Firmware only"], "answer": [1], "explanation": "Full OS on emulated hardware, isolated by the hypervisor."}, {"id": "27.3", "q": "What connects VM vNICs to each other and to physical NICs on a host?", "options": ["A virtual switch (vSwitch)", "An external router only", "USB passthrough", "The BIOS"], "answer": [0], "explanation": "vSwitches do L2 forwarding in software (typically no STP; loop prevention by design)."}, {"id": "27.4", "q": "How do containers differ from VMs?", "options": ["Containers include a full guest OS", "Containers share the host kernel and isolate at the process level — lighter and faster to start", "Containers are slower", "No difference"], "answer": [1], "explanation": "Shared kernel, process isolation, small images — vs. full OS per VM."}, {"id": "27.5", "q": "In NFV terminology, a virtualized router or firewall image (e.g., Catalyst 8000V) is called a:", "options": ["VTEP", "VNF (virtual network function)", "VRF", "vSmart"], "answer": [1], "explanation": "VNFs are the virtualized network functions; NFVI/VIM provide infrastructure and management."}, {"id": "27.6", "q": "Cisco Enterprise NFV (ENFV) lets a branch:", "options": ["Replace all hardware with cloud services", "Run router/firewall/WLC functions as VNFs on a single x86 platform (NFVIS)", "Eliminate WAN links", "Run only containers"], "answer": [1], "explanation": "ENFV consolidates branch services onto NFVIS-based x86 hosts."}]}, {"num": 28, "title": "Network Programmability (4.6, 5.3, 6.1, 6.2, 6.3, 6.4, 6.5)", "questions": [{"id": "28.1", "q": "Which HTTP methods map to CRUD operations in a REST API?", "options": ["POST=create, GET=read, PUT/PATCH=update, DELETE=delete", "GET=create, POST=read", "PUT=read, GET=update", "DELETE=create"], "answer": [0], "explanation": "POST create, GET read, PUT replace / PATCH modify, DELETE remove. REST is stateless."}, {"id": "28.2", "q": "Interpret these REST response codes: 200, 201, 401, 404, 500.", "options": ["200 OK, 201 Created, 401 Unauthorized, 404 Not Found, 500 Server Error", "200 Created, 201 OK, 401 Not Found, 404 Unauthorized, 500 OK", "All success codes", "All client errors"], "answer": [0], "explanation": "2xx success, 4xx client-side (401 auth missing/bad, 403 forbidden, 404 missing), 5xx server-side."}, {"id": "28.3", "q": "Which JSON snippet is valid?", "options": ["{\"hostname\": \"SW1\", \"ports\": [1, 2, 3]}", "{hostname: SW1}", "{\"hostname\" = \"SW1\"}", "{\"ports\": (1,2,3)}"], "answer": [0], "explanation": "Keys quoted, string values quoted, arrays in [ ], no = signs, no trailing commas."}, {"id": "28.4", "q": "In JSON, square brackets vs curly braces represent:", "options": ["[ ] = ordered array/list; { } = object of key:value pairs", "[ ] = object; { } = array", "Both are arrays", "Both are objects"], "answer": [0], "explanation": "Arrays are ordered lists; objects are unordered key:value maps."}, {"id": "28.5", "q": "What is YANG?", "options": ["A transport protocol", "A data modeling language defining the structure/types of config and state data, used by NETCONF/RESTCONF", "An encryption standard", "A Python library"], "answer": [1], "explanation": "YANG models the data; NETCONF/RESTCONF transport it."}, {"id": "28.6", "q": "NETCONF vs RESTCONF transport and encoding:", "options": ["NETCONF = SSH (port 830) + XML and RPC operations/datastores; RESTCONF = HTTPS + JSON or XML using HTTP verbs", "NETCONF = HTTP + JSON; RESTCONF = SSH + XML", "Both use SNMP", "Both are XML-only"], "answer": [0], "explanation": "Know both stacks cold: 830/SSH/XML/RPC vs HTTPS//restconf/data with JSON (YANG-driven URLs)."}, {"id": "28.7", "q": "Which NETCONF datastore holds config that can be validated/committed before applying?", "options": ["running", "candidate", "startup", "volatile"], "answer": [1], "explanation": "Candidate allows validate/commit (with rollback); running is live; startup survives reboot."}, {"id": "28.8", "q": "How do you authenticate to the Catalyst Center (DNA Center) REST API?", "options": ["SNMP community", "POST credentials to the token endpoint, then send the X-Auth-Token header on subsequent calls", "Telnet login", "No auth needed"], "answer": [1], "explanation": "Token-based auth: authenticate once, reuse the token in headers."}, {"id": "28.9", "q": "Which practices secure a REST API? (Choose three.)", "options": ["TLS/HTTPS for transport encryption", "Token/OAuth-based authentication with least-privilege authorization", "Rate limiting/throttling", "Embedding admin credentials in client-side code"], "answer": [0, 1, 2], "explanation": "Encrypt, authenticate/authorize minimally, throttle. Never hardcode credentials."}, {"id": "28.10", "q": "In Python, `response = requests.get(url); data = response.json()` — `data[\"devices\"][0][\"hostname\"]` returns:", "options": ["The \"hostname\" value of the first element in the \"devices\" list", "A syntax error", "All hostnames", "The HTTP status code"], "answer": [0], "explanation": "Dict/list indexing into parsed JSON — the pattern ENCOR loves to test."}, {"id": "28.11", "q": "Refer to the API exchange. What should the script do next?", "options": ["Retry the same request — 401 is a transient server error", "Re-authenticate to the token endpoint and resend with a fresh X-Auth-Token header — 401 means the credentials/token were missing, invalid, or expired", "Treat it as success; data follows", "Switch from GET to POST"], "exhibit": "GET https://catalystcenter.example.com/dna/intent/api/v1/network-device\n--- response ---\nHTTP/1.1 401 Unauthorized\n{\n  \"response\": {\n    \"errorCode\": \"INVALID_CREDENTIALS\",\n    \"message\": \"Authentication token is invalid or expired\"\n  }\n}", "answer": [1], "explanation": "401 = authentication problem (vs 403 = authenticated but not allowed). Catalyst Center tokens expire; re-auth and retry is the standard pattern."}, {"id": "28.12", "q": "Refer to the RESTCONF response. What is the state of GigabitEthernet1?", "options": ["The request failed", "The request succeeded (200), and the interface is administratively disabled (\"enabled\": false) with IP 10.0.0.1/24 configured", "The interface is up with no IP", "200 means the interface is operationally up"], "exhibit": "HTTP/1.1 200 OK\nContent-Type: application/yang-data+json\n\n{\n  \"ietf-interfaces:interface\": {\n    \"name\": \"GigabitEthernet1\",\n    \"type\": \"iana-if-type:ethernetCsmacd\",\n    \"enabled\": false,\n    \"ietf-ip:ipv4\": {\n      \"address\": [{ \"ip\": \"10.0.0.1\", \"netmask\": \"255.255.255.0\" }]\n    }\n  }\n}", "answer": [1], "explanation": "The status code describes the API call, not the interface. The YANG data shows admin state false = shutdown, with an IPv4 address configured."}]}, {"num": 29, "title": "Automation Tools (6.6, 6.7)", "questions": [{"id": "29.1", "q": "Where does an EEM applet run?", "options": ["On Catalyst Center", "Locally on the IOS device itself", "On an external server", "In the cloud"], "answer": [1], "explanation": "EEM is on-box automation: events (syslog, CLI, timers, SNMP, track) trigger local actions."}, {"id": "29.2", "q": "Which EEM applet reacts to a syslog message and runs commands?", "options": ["event manager applet X / event syslog pattern \"...\" / action 1.0 cli command \"...\"", "kron policy-list", "ip sla schedule", "snmp-server enable traps"], "answer": [0], "explanation": "Classic applet structure: one event statement, ordered action statements."}, {"id": "29.3", "q": "In EEM, actions execute in what order?", "options": ["Random", "Alphanumeric order of the action labels (1.0, 1.5, 2.0...)", "Reverse order", "Simultaneously"], "answer": [1], "explanation": "Labels sort alphanumerically — number them with room to insert (1.0, 2.0, ...)."}, {"id": "29.4", "q": "Agent-based vs agentless: which pairing is correct?", "options": ["Puppet/Chef = agent-based (pull model); Ansible = agentless (push over SSH)", "Ansible = agent-based; Puppet = agentless", "All require agents", "All are agentless"], "answer": [0], "explanation": "Puppet/Chef install agents that pull from a master; Ansible pushes via SSH/NETCONF/API. (SaltStack: agent (minion) or agentless via salt-ssh.)"}, {"id": "29.5", "q": "Ansible playbooks are written in which format, and what property makes re-running them safe?", "options": ["XML; transactions", "YAML; idempotency (only changes what differs from desired state)", "JSON; locking", "INI; backups"], "answer": [1], "explanation": "YAML playbooks; idempotent modules converge devices to desired state."}, {"id": "29.6", "q": "Why is an agentless tool often preferred for network devices?", "options": ["Agents are faster", "Most network OSs can't easily run third-party agents; SSH/API push works with existing access", "Agentless tools need no credentials", "It isn't preferred"], "answer": [1], "explanation": "No agent footprint on IOS/NX-OS; reuses SSH/HTTPS management plane."}]}];
